﻿<!DOCTYPE html>
<html lang="en">

<head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <BasePath />
    <ResourcePreloader />
    <link rel="stylesheet" href="@Assets["lib/bootstrap/dist/css/bootstrap.min.css"]" />
    <link rel="stylesheet" href="@Assets["app.css"]" />
    <link rel="stylesheet" href="@Assets["BlazorApp.styles.css"]" />
    <ImportMap />
    <link rel="icon" type="image/png" href="favicon.png" />
    <HeadOutlet @rendermode="PageRenderMode" />
</head>

<body>
    <Routes @rendermode="PageRenderMode" />
    <ReconnectModal />
    <script src="@Assets["_framework/blazor.web.js"]"></script>
</body>

</html>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode =>
        HttpContext?.GetEndpoint()?.Metadata.GetMetadata<RenderModeAttribute>()?.Mode
            ?? RenderModeInteractiveServer.Instance;

    // Returns null (static SSR) for pages decorated with @attribute [RenderModeAttribute(null)]
    // or the custom ExcludeFromInteractiveRoutingAttribute; otherwise defaults to InteractiveServer.

    private static class RenderModeInteractiveServer
    {
        public static InteractiveServerRenderMode Instance { get; } = new();
    }
}

