namespace BlazorApp;

/// <summary>
/// When applied to a routable page component, this attribute signals App.razor
/// to render the page with static SSR (render mode = null) instead of the
/// global InteractiveServer mode. This allows the page to access HttpContext.
/// </summary>
[AttributeUsage(AttributeTargets.Class)]
public sealed class ExcludeFromInteractiveRoutingAttribute : Attribute;

@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [BlazorApp.ExcludeFromInteractiveRouting]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success" role="alert">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>Cookie Usage</h2>
<p>
    This site uses cookies to improve your experience. By continuing to use this
    site you consent to the use of cookies in accordance with this policy.
</p>

<h2>What Data We Collect</h2>
<p>
    We collect only the minimum information necessary to provide our services,
    including a consent cookie that records whether you have accepted this policy.
</p>

<h2>Your Rights</h2>
<p>
    You may withdraw your consent at any time by clearing your browser cookies.
</p>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented =>
        HttpContext?.Request.Cookies.ContainsKey("consent") is true;
}

